const raw = $input.item.json.message?.content ?? $input.item.json.choices?.[0]?.message?.content ?? '';

let parsed;
try {
  // Limpiar posible markdown de code block si el modelo lo incluye
  const cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  return [{ json: { __error: true, __reason: 'JSON_PARSE_FAILED', __raw: raw.slice(0, 500), slug: $('Set: Preparar variables del prompt').item.json.slug } }];
}

// Validacion de campos obligatorios
const required = ['intro_unica', 'analisis_fiscal_personalizado', 'h2_variante', 'conclusion_local', 'narrativa_angulo'];
const missing = required.filter(k => !parsed[k]);
if (missing.length > 0) {
  return [{ json: { __error: true, __reason: 'MISSING_FIELDS:' + missing.join(','), slug: $('Set: Preparar variables del prompt').item.json.slug } }];
}

// Validar h2_variante es array de 3 elementos
if (!Array.isArray(parsed.h2_variante) || parsed.h2_variante.length !== 3) {
  return [{ json: { __error: true, __reason: 'H2_VARIANTE_INVALID', slug: $('Set: Preparar variables del prompt').item.json.slug } }];
}

// Validar longitud minima de intro (200 palabras en total aproximado)
const introWords = (parsed.intro_unica || '').split(' ').length;
const analisisWords = (parsed.analisis_fiscal_personalizado || '').split(' ').length;
const conclusionWords = (parsed.conclusion_local || '').split(' ').length;
const totalWords = introWords + analisisWords + conclusionWords;

if (totalWords < 200) {
  return [{ json: { __error: true, __reason: 'CONTENT_TOO_SHORT:' + totalWords + '_words', slug: $('Set: Preparar variables del prompt').item.json.slug } }];
}

const vars = $('Set: Preparar variables del prompt').item.json;

return [{
  json: {
    __error: false,
    slug:                          vars.slug,
    municipio:                     vars.municipio,
    provincia:                     vars.provincia,
    comunidad_autonoma:            vars.comunidad_autonoma,
    // Contenido IA
    intro_unica:                   parsed.intro_unica,
    analisis_fiscal_personalizado: parsed.analisis_fiscal_personalizado,
    h2_variante:                   parsed.h2_variante,
    conclusion_local:              parsed.conclusion_local,
    narrativa_angulo:              parsed.narrativa_angulo,
    calidad_score:                 parseFloat(parsed.calidad_score) || null,
    palabras_total:                totalWords,
    modelo_ia:                     'gpt-4o-mini',
    version_prompt:                1,
    // Snapshot datos fuente
    irradiacion_solar:             parseFloat(vars.irradiacion) || null,
    horas_sol:                     parseInt(vars.horas_sol) || null,
    ahorro_estimado:               parseFloat(vars.ahorro) || null,
    bonificacion_ibi:              parseFloat(vars.ibi) || null,
    subvencion_autoconsumo:        parseFloat(vars.subvencion) || null,
    precio_instalacion_medio_eur:  parseFloat(vars.precio_instalacion) || null,
    precio_medio_luz:              parseFloat(vars.precio_luz) || null,
    habitantes:                    parseInt(vars.habitantes) || null
  }
}];
